  'changzhou/dino': ('حديقة الديناصورات', 'تُعد أشهر حديقة ترفيهية للديناصورات في الصين، وهي رمز المدينة المفضل للعائلات.'),
  'changzhou/pagoda': ('باغودا تياننينغ', 'ترتفع هذه الباغودا في وسط المدينة لتكون الأطول في العالم بطول يصل إلى 153 متراً.'),
  'changzhou/comb': ('حرفة الأمشاط', 'كانت أمشاط تشانغتشو التي يعود تاريخها إلى ألف عام تُقدم قديماً كهدايا ملكية.'),
  'changzhou/canal': ('القناة الكبرى', 'يستمتع الزوار بالتنزه على ضفاف القناة لاستكشاف الأحياء القديمة ومشاهدة أضواء الليل.'),
  'shaoxing/wine': ('نبيذ شاوشينغ', 'يُصنع هنا منذ آلاف السنين نبيذ الأرز الأصفر الشهير الذي يُعد عنصراً أساسياً في المطبخ الصيني.'),
  'shaoxing/bridge': ('الجسور الحجرية', 'تحتفظ مدينة شاوشينغ، التي تتخللها القنوات المائية، بمئات الجسور الحجرية المقوسة.'),
  'shaoxing/pen': ('مهد الخط العربي الصيني', 'يُعتبر جناح الأوركيد الخاص بالخطاط الشهير وانغ شي تشي موقعاً مقدساً لفن الخط.'),
  'shaoxing/boat': ('قوارب ووبنغ', 'تُعد قوارب "ووبنغ" ذات المظلات السوداء، التي تُدفع بالأقدام، وسيلة التنقل الكلاسيكية في القنوات المائية.'),
  'bengbu/shell': ('ميناء اللؤلؤ', 'يعني اسم المدينة "رصيف المحار"، وقد اشتهرت قديماً بإنتاج لآلئ نهر هواي.'),
  'bengbu/train': ('بوابة السكك الحديدية', 'تعد مدينة بنغبو نقطة عبور رئيسية لخطوط السكك الحديدية بين شمال الصين وجنوبها، وقد ازدهرت المدينة بفضل محطتها المركزية.'),
  'bengbu/river': ('نهر هواي', 'يجري نهر هواي عبر هذه المدينة، وهو النهر الذي يُعتبر تاريخياً الفاصل الطبيعي بين شمال الصين وجنوبها.'),
  'bengbu/blossom': ('مهرجانات الربيع', 'تكتسي المتنزهات المطلة على ضفاف النهر بحلة زاهية خلال مهرجانات الزهور التي تقام في كل ربيع.'),
  'jiujiang/mountain': ('جبل لو', 'ألهمت قمم جبل لو الضبابية، المدرج ضمن قائمة اليونسكو للتراث العالمي، أجيالاً من الشعراء والرسامين الصينيين.'),
  'jiujiang/tea': ('شاي السحاب والضباب', 'يُعد شاي "يون وو" المستخلص من منحدرات جبل لو واحداً من أرقى وأجود أنواع الشاي في الصين.'),
  'jiujiang/lake': ('بحيرة بويانغ', 'تعد بحيرة بويانغ أكبر بحيرة للمياه العذبة في الصين، وتستقبل آلاف الطيور المهاجرة خلال فصل الشتاء.'),
  'jiujiang/scroll': ('مدينة القصائد', 'تزخر هذه المدينة الواقعة على ضفاف النهر بآثار أدبية خلدت قصائد كبار الشعراء مثل باي جويي وسو شي.'),
  'quanzhou/ship': ('طريق الحرير البحري', 'كانت مدينة تشوانتشو، المعروفة تاريخياً باسم "زيتون"، أعظم ميناء في العالم خلال العصور الوسطى وهي مدرجة ضمن قائمة اليونسكو.'),
  'quanzhou/mosque': ('مسجد تشينغجينغ', 'يُعد مسجد تشينغجينغ الحجري، الذي شُيد عام 1009 ميلادي، واحداً من أقدم المساجد في الصين.'),
  'quanzhou/puppet': ('فن العرائس', 'يُعتبر فن تحريك العرائس بالخيوط في تشوانتشو تقليداً مسرحياً عريقاً يعود تاريخه إلى ألف عام.'),
  'quanzhou/tea': ('شاي تيغوانين', 'يُعرف شاي الأولونغ القادم من منطقة أنشي المجاورة عالمياً باسم شاي "الإلهة الحديدية".'),
  'shanghai/pearl': ('برج لؤلؤة الشرق', 'يُعد هذا البرج، بكراته الوردية الشاهقة فوق نهر هوانغبو، الرمز الأبرز لمدينة شنغهاي الحديثة.'),
  'shanghai/bund': ('منطقة البوند', 'تعكس واجهات الفنادق والمباني التاريخية المطلة على ضفاف النهر عظمة شنغهاي في الماضي.'),
  'shanghai/garden': ('حديقة يو', 'تعتبر حديقة يو الكلاسيكية، التي تعود إلى عهد أسرة مينغ، واحة من الصخور والبرك في قلب المدينة الصاخب.'),
  'shanghai/xlb': ('زلابية الحساء', 'تُعد هذه الفطائر المطهوة على البخار والمحشوة بالمرق الساخن تحفة فنية في مائدة إفطار شنغهاي.'),
  'hangzhou/lake': ('البحيرة الغربية', 'تعد هذه البحيرة، بما تضمه من أشجار الصفصاف والجزر والجسور المقوسة، أكثر البحيرات التي تغنى بها الشعراء الصينيون.'),
  'hangzhou/tea': ('شاي لونغجينغ', 'يُعد شاي "بئر التنين" الأخضر، الذي يُزرع على المنحدرات المحيطة بالبحيرة، أشهر أنواع الشاي في الصين.'),
  'hangzhou/temple': ('معبد لينغين', 'يشتهر هذا المعبد الذي يعود تاريخه إلى 1700 عام، والمعروف بـ "معبد ملاذ الروح"، بنقوشه الصخرية وتمثال بوذا العملاق.'),
  'hangzhou/silk': ('مدينة الحرير', 'يُنسج حرير هانغتشو منذ ألف عام، وهو الذي شكل ثروة الطرف الشرقي لطريق الحرير التاريخي.'),
  'chongqing/hongya': ('كهف هونغيا', 'مجمع من المنازل التقليدية المشيدة على ركائز متينة فوق المنحدر الصخري، ويتلألأ ليلاً فوق النهر كأنه مشهد من القصص الخيالية.'),
  'chongqing/hotpot': ('قدر تشونغتشينغ الساخن', 'يُعتبر هذا الطبق، الذي يغلي بالزيت الحار والفلفل المخدر، الروح النارية لمدينة الجبال.'),
  'chongqing/monorail': ('قطار تشونغتشينغ المعلق', 'يُعد القطار الخفيف الذي يخترق المباني السكنية المشهد الأبرز لهذه المدينة المبنية فوق التلال.'),
  'chongqing/river': ('مضايق اليانغتسي', 'تنطلق رحلات السفن السياحية عبر المضايق الثلاثة من هذا الميناء، حيث ترتفع المدينة عند ملتقى نهرين عظيمين.'),
  'dalian/square': ('ميدان شينغهاي', 'يُعد أكبر ميدان في آسيا، ويضج بالمهرجانات والعروض الفنية على طول الواجهة البحرية.'),
  'dalian/beach': ('شواطئ داليان', 'بفضل خلجانها الصخرية وصيفها المعتدل، تُعتبر داليان الوجهة الساحلية المفضلة في شمال الصين.'),
  'dalian/football': ('مدينة كرة القدم', 'تُلقب بـ "مهد كرة القدم" في الصين، حيث نشأت فيها أكثر الأندية تتويجاً بالألقاب في البلاد.'),
  'dalian/seafood': ('مأكولات داليان البحرية', 'تتزين موائد المدينة بأشهى المأكولات البحرية من مياه البحر الأصفر الباردة، مثل الإسقلوب والروبيان وقنفذ البحر.'),
  'shenyang/palace': ('قصر موكدين', 'هو القصر الأول لسلالة تشينغ، ويُعتبر بمثابة الشقيق الأصغر للمدينة المحرمة في بكين.'),
  'shenyang/tomb': ('مقابر تشينغ', 'تُعد المقابر الشرقية والشمالية التي تحيط بالمدينة أضرحة أثرية لمؤسسي سلالة تشينغ.'),
  'shenyang/factory': ('مهد الصناعة', 'وُلدت الصناعات الثقيلة الصينية هنا، وقد أكسبتها مصانعها الضخمة لقب "رور الشرق".'),
  'shenyang/dumpling': ('زلابية لاوبيان', 'تُعد زلابية لاوبيان المطهوة على البخار، والتي يعود تاريخها إلى مئتي عام، الطبق المميز على المائدة الشمالية.'),
  'hefei/judge': ('ضريح القاضي باو', 'وُلد القاضي العادل باو تشنغ في هذه المدينة، ويُعتبر ضريحه رمزاً للنزاهة والاستقامة.'),
  'hefei/science': ('مدينة العلوم', 'تُعد هذه المدينة مركزاً تقنياً يضم نخبة من الجامعات والمختبرات الرائدة في الصين.'),
  'hefei/lake': ('بحيرة تشاوهو', 'تُصنف كواحدة من أكبر خمس بحيرات للمياه العذبة في الصين، وتشتهر بأسماكها البيضاء وسرطان البحر.'),
  'hefei/cake': ('كعكة السمسم لو', 'تعتبر كعكة السمسم المحشوة بالحلوى من أقدم الحلويات التقليدية في مدينة لوتشو العريقة.'),
  'foshan/wingchun': ('وينغ تشون', 'تُعد المدينة موطن فن الوينغ تشون القتالي، حيث تعود إليها جذور المعلم ييب مان وبروس لي.'),
  'foshan/lion': ('رقصة الأسد', 'تُلقب المدينة بعاصمة رقصة الأسد الجنوبية، حيث تتقافز الأسود الملونة فوق الأعمدة في استعراضات مبهرة.'),
  'foshan/ceramic': ('خزف شيوان', 'لا تزال أفران الخزف التي يعود تاريخها إلى ألف عام تنتج تماثيل شيوان الحيوية.'),
  'foshan/opera': ('أوبرا كانتونية', 'نشأ هذا الفن المسرحي الأكثر شعبية في جنوب الصين وتطور على هذه الأرض.'),
  'guiyang/pavilion': ('جناح جياشيو', 'يُعد هذا الجناح المكون من ثلاث طبقات والمطل على نهر نانمينغ رمزاً للمدينة منذ أربعمئة عام.'),
  'guiyang/sourfish': ('سمك الحساء الحامض', 'يُعد السمك المطهو في مرق الطماطم المخمرة الحامض الطبق الأكثر تميزاً في مقاطعة قويتشو.'),
  'guiyang/waterfall': ('شلالات هوانغغوشو', 'تُعد واحدة من أكبر شلالات آسيا، حيث تتدفق مياهها بقوة لتشكل أقواس قزح خلابة.'),
  'guiyang/miao': ('ثقافة مياو', 'تضفي مهرجانات شعب المياو المتوجين بالفضة وفنون التطريز الخاصة بهم البهجة على القرى الجبلية.'),
  'changchun/film': ('مدينة السينما', 'تضم المدينة الاستوديوهات التي وُلدت فيها السينما الصينية، وتُعرف بلقب هوليوود الشرق.'),
  'changchun/car': ('مدينة السيارات', 'خرجت أول سيارة صينية الصنع من مصانع هذه المدينة التي تُعد العاصمة الوطنية لصناعة السيارات.'),
  'changchun/palace': ('قصر الإمبراطور الأخير', 'يعد هذا القصر الذي عاش فيه آخر أباطرة الصين شاهداً صامتاً على حقبة تاريخية مضطربة.'),
  'changchun/snow': ('ثلوج الشتاء', 'تتألق المدينة خلال فصول الشتاء الطويلة بمنحوتاتها الجليدية ومسارات التزلج البيضاء.'),
  'xining/lake': ('بحيرة تشينغهاي', 'تُعرف أكبر بحيرة مالحة في الصين بحقول زهور اللفت الصفراء التي تحيط بها في فصل الصيف.'),
  'xining/monastery': ('دير كومبوم', 'يُعد أحد الأديرة الستة الكبرى للبوذية التبتية، ويشتهر بمنحوتاته المصنوعة من زبدة الياك.'),
  'xining/flower': ('زهور اللفت', 'تكتسي الهضبة في شهر يوليو بحقول ذهبية من زهور اللفت تمتد حتى الأفق.'),
  'xining/lamb': ('لحم الياك والضأن', 'تتميز نكهات الهضبة بأطباق المعكرونة المسحوبة يدوياً وأسياخ لحم الضأن المستوحاة من مطبخ قوميتي هوي والتبت.'),
  'guilin/karst': ('تضاريس نهر لي الكارستية', 'تعد القمم الكلسية التي تبرز من بين الضباب المشهد المطبوع على ورقة العشرين يوان النقدية.'),
  'guilin/elephant': ('تلة جذع الفيل', 'تعتبر الصخرة التي تتخذ شكل فيل يغمس خرطومه في النهر الرمز المحبوب للمدينة.'),
  'guilin/terrace': ('مصاطب لونغجي للأرز', 'تُشكل مصاطب \'عمود فقري للتنين\' التي تلتف حول المنحدرات سلماً يعكس قروناً من الكدح البشري.'),
  'guilin/osmanthus': ('زهور الأوسمانثوس', 'يعني اسم المدينة \'غابة الأوسمانثوس\'، حيث تغرق المدينة في فصل الخريف بعبير زهورها العطرة.'),
  'wenzhou/merchant': ('روح التجارة', 'يُعرف رواد الأعمال في ونتشو ببراعتهم التجارية، حيث أسسوا شبكات أعمال تمتد في جميع أنحاء العالم.'),
  'wenzhou/shoe': ('الأحذية والجلود', 'تنتج هذه المدينة الصناعية حصة ضخمة من الأحذية الجلدية التي تُباع في الأسواق العالمية.'),
  'wenzhou/mountain': ('جبال ياندانغ', 'تُعرف هذه الجبال بشلالاتها وقممها المسننة، وتُلقب بـ \'الجبل الأول المطل على البحر\'.'),
  'wenzhou/seafood': ('المأكولات البحرية', 'تشكل الأسماك والمحار والحبار المستخرجة من بحر الصين الشرقي الركيزة الأساسية للمائدة المحلية.'),
  'tangshan/memorial': ('نصب تذكاري للزلزال', 'يعد النصب التذكاري لزلزال عام 1976 الكبير رمزاً لمدينة ولدت من جديد.'),
  'tangshan/coal': ('منجم الفحم والصلب', 'تُعد هذه المدينة مهد الصناعة الصينية، حيث افتُتح فيها أول منجم فحم وسكة حديدية حديثة في البلاد.'),
  'tangshan/ceramic': ('خزف تانغشان', 'تُلقب المدينة بـ "عاصمة الخزف في الشمال"، وتتميز بصناعة الخزف العظمي الذي يضفي لمسة من الأناقة على الموائد.'),
  'tangshan/lake': ('حديقة نانهو', 'تحولت حفرة منجم قديمة إلى حديقة بحيرة خلابة أصبحت بمثابة الرئة الخضراء للمدينة.'),
  'anshan/steel': ('مدينة الصلب', 'تأسست هنا أكبر مصانع الصلب في الصين، مما جعل المدينة تُعرف بلقب "عاصمة الصلب" في البلاد.'),
  'anshan/jade': ('يشم شيويان', 'تضم المدينة أكبر منحوتة يشم في العالم، وتُعتبر الموطن الرئيسي لليشم في الصين.'),
  'anshan/mountain': ('جبل تشيان', 'يُعرف الجبل بـ "قمم اللوتس الألف"، وهو قمة مقدسة في الشمال تشتهر بمعابدها وتضاريسها الصخرية.'),
  'anshan/spring': ('ينابيع تانغغانغزي', 'ينابيع حارة يقصدها الناس للاستشفاء منذ ألف عام، وقد كانت وجهة مفضلة للأباطرة قديماً.'),
  'linyi/market': ('سوق الجملة', 'يُعد هذا السوق أكبر مركز لتجارة الجملة في شمال الصين، حيث تُشحن البضائع منه إلى جميع أنحاء البلاد.'),
  'linyi/brush': ('سيد الخط العربي', 'وُلد هنا وانغ شي تشي، الملقب بـ "حكيم الخط" في الصين، وتُعرف المدينة بكونها أرض الحبر والفن.'),
  'linyi/mountain': ('جبل منغ', 'يُعد ثاني أعلى جبل في مقاطعة شاندونغ، وهو بمثابة منتجع طبيعي غني بالهواء النقي والشلالات.'),
  'linyi/pancake': ('فطائر ييمينغ', 'تُعتبر فطائر الذرة الرقيقة "جيان بينغ" الغذاء الأساسي التقليدي لسكان جبال ييمينغ منذ القدم.'),
  'cangzhou/lion': ('الأسد الحديدي', 'يُعد تمثال الأسد الحديدي الضخم الذي يعود تاريخه إلى 1100 عام رمزاً للفخر في المدينة.'),
  'cangzhou/martial': ('الفنون القتالية', 'تُلقب المدينة بـ "موطن الووشو" في الصين، حيث خرج منها أشهر أساتذة الفنون القتالية ومدارسها.'),
  'cangzhou/canal': ('القناة الكبرى', 'تمر القناة الكبرى الرابطة بين بكين وهانغتشو عبر المدينة، ولا تزال أرصفتها القديمة قائمة حتى اليوم.'),
  'cangzhou/jujube': ('العناب الذهبي', 'يُعرف العناب ذو القشرة الرقيقة والمذاق الحلو بلقب "ملك الفواكه المجففة".'),
  'nantong/textile': ('مدينة المنسوجات', 'تُعد نانتونغ عاصمة المنسوجات المنزلية في الصين، حيث تصل أقمشتها القطنية إلى الأسواق في جميع أنحاء العالم.'),
  'nantong/mountain': ('جبل لانغ', 'يرتفع هذا الجبل المقدس ذو القمم الخمس عند مصب نهر يانغتسي، ويُعد وجهة شهيرة للحج والاستمتاع بالمناظر الطبيعية.'),
  'nantong/kite': ('طائرة بانيو الورقية', 'تُعتبر طائرات "بانيو" الورقية المزودة بصفارات طنين حرفة تقليدية عريقة تشتهر بها المدينة.'),
  'nantong/school': ('رائد التعليم', 'أسس الصناعي تشانغ جيان هنا أول مدارس ومتحف حديث في الصين.'),
  'taizhou/opera': ('مي لان فانغ', 'تُعد هذه المدينة مسقط رأس مي لان فانغ، الأستاذ الأسطوري لأوبرا بكين.'),
  'taizhou/tea': ('شاي الصباح', 'يُعتبر طقس "زوتشا" الصباحي، الذي يجمع بين تناول الكعك المطهو على البخار وشرب الشاي، جزءاً أصيلاً من ثقافة المدينة.'),
  'taizhou/boat': ('مهرجان قوارب تشينتونغ', 'في فصل الربيع، يبعث مهرجان سباق القوارب الذي يشارك فيه مئات المجدفين الحياة في النهر.'),
  'taizhou/meatball': ('كرات لحم رأس الأسد', 'تُعد كرات لحم الخنزير الكبيرة والطرية المعروفة باسم "رأس الأسد" طبقاً كلاسيكياً من مطبخ هوايانغ.'),
  'jinhua/ham': ('لحم جينهوا المقدد', 'يُعد هذا اللحم الأحمر، الذي يُعالج بطريقة تعود لقرون مضت، الأشهر من نوعه في الصين.'),
  'jinhua/film': ('استوديوهات هنغديان', 'تُعد أكبر موقع تصوير سينمائي خارجي في العالم، حيث يتم تصوير عدد لا يحصى من الأعمال الدرامية التاريخية.'),
  'jinhua/cave': ('كهف شوانغلونغ', 'كهف تحت الأرض يخطف الأنفاس، يتم الدخول إليه بالقوارب عبر بوابة صخرية منخفضة.'),
  'jinhua/bridge': ('الجسور القديمة', 'تجسد الجسور الحجرية المقوسة والبلدات المائية سحر منطقة جيانغنان وجمالها.'),
  'wuhu/park': ('فانغتي وندرلاند', 'تُعد واحدة من أكبر مدن الملاهي في الصين، وتوفر للعائلات أياماً مليئة بالإثارة والمرح.'),
  'wuhu/ironart': ('الرسم بالحديد', 'تُعتبر لوحات "الرسم بالحديد" الأنيقة والمصنوعة من الحديد المطاوع حرفة يدوية يعود تاريخها إلى 300 عام.'),
  'wuhu/rice': ('ميناء الأرز', 'كانت هذه المدينة الواقعة على ضفاف نهر يانغتسي تاريخياً أكبر سوق للأرز في الصين.'),
  'wuhu/river': ('ميناء يانغتسي', 'يُعد هذا الميناء النهري النشط البوابة الرئيسية لمدينة ووهو نحو البحر.'),
  'huangshan/peak': ('الجبل الأصفر', 'يُعتبر الجبل الأشهر في الصين بفضل قمم الجرانيت وبحر السحب وأشجار الصنوبر الملتوية.'),
  'huangshan/village': ('قرية هونغ تسون', 'تُصنف هذه القرية ذات الجدران البيضاء والمجاري المائية ضمن قائمة اليونسكو للتراث العالمي، وتبدو كأنها لوحة فنية.'),
  'huangshan/tea': ('شاي ماوفنغ', 'يُقطف هذا الشاي الأخضر ذو البراعم الزغبية من المنحدرات الضبابية، ويُصنف ضمن أنواع الشاي العشرة الأكثر شهرة في الصين.'),
  'huangshan/ink': ('حبر وفنون هويتشو', 'يُعد حبر هوي والمنازل الخشبية المنحوتة وفن الخط من الكنوز الثقافية لهذه المنطقة.'),
  'yichun/moon': ('جبل مينغيو', 'يشتهر جبل \'القمر الساطع\' بينابيعه الحارة وإطلالاته البانورامية عبر التلفريك.'),
  'yichun/spring': ('الينابيع الحارة', 'جعلت الينابيع الحارة النادرة والغنية بالسيلينيوم من المدينة مركزاً للاستشفاء في الصين.'),
  'yichun/zen': ('بوذية تشان', 'تدعو المعابد الجبلية المتجذرة في طوائف \'تشان\' الصينية الزوار إلى التأمل والسكينة.'),
  'yichun/rice': ('سهل الأرز', 'لطالما كان سهل يوان-هي الخصيب بمثابة سلة الغذاء لمقاطعة جيانغشي.'),
  'zhangzhou/narcissus': ('زهرة النرجس', 'تنمو هنا أشهر أبصال النرجس في الصين، والتي تُعد رمزاً لاحتفالات الربيع.'),
  'zhangzhou/tulou': ('بيوت التولو', 'تُعد هذه القلاع الدائرية الضخمة المصنوعة من التربة المدكوكة موقعاً تراثياً لليونسكو، وتجمع القرية بأكملها تحت سقف واحد.'),
  'zhangzhou/banana': ('الفواكه الاستوائية', 'تحافظ بساتين الموز واللونغان واليوسفي على اخضرار الدلتا الدافئة طوال العام.'),
  'zhangzhou/coast': ('جزيرة دونغشان', 'تُعتبر الجزيرة جوهرة الساحل الجنوبي بفضل شواطئها الذهبية وقراها التي يعمل سكانها في صيد الأسماك.'),
  'guangzhou/tower': ('برج كانتون', 'يُعرف ببرج \'الخصر النحيل\'، وهو أحد أطول الأبراج في العالم، ويتوج المدينة بألوانه المتغيرة ليلاً.'),
  'guangzhou/dimsum': ('شاي الصباح', 'يُعد \'يام تشا\' - وهو الديم سام المطهو على البخار في سلال الخيزران مع الشاي - روح المائدة الكانتونية.'),
  'guangzhou/academy': ('أكاديمية عشيرة تشن', 'تُعد قاعة العشيرة هذه تحفة فنية من الحرف الكانتونية، وتشتهر بمنحوتاتها الخشبية وزخارفها الخزفية البديعة.'),
  'guangzhou/flower': ('مدينة الزهور', 'تُلقب غوانزو بـ "مدينة الزهور" نظراً لأزهارها التي تتفتح طوال العام، وإقامة معارض الزهور الضخمة فيها مع مطلع كل عام جديد.'),
  'wuhan/crane': ('برج الرافعة الصفراء', 'يطل هذا البرج الذي يعود تاريخه إلى ألف عام على نهر يانغتسي، وقد كان مصدراً لإلهام أشهر القصائد الصينية.'),
  'wuhan/noodle': ('نودلز ساخنة وجافة', 'تُعتبر النودلز الساخنة والجافة الممزوجة بمعجون السمسم وجبة الإفطار الأساسية التي لا غنى عنها في ووهان.'),
  'wuhan/duckneck': ('رقبة البط الحارة', 'تُعد رقبة البط المطهوة بالتوابل الحارة الوجبة الخفيفة المفضلة لدى سكان المدينة خلال جلسات السمر الليلية.'),
  'wuhan/university': ('أزهار الكرز في الحرم الجامعي', 'تجذب أزهار الكرز في جامعة ووهان آلاف الزوار للاستمتاع بجمالها في كل ربيع.'),
  'tianjin/eye': ('عين تيانجين', 'هي عجلة ترفيهية ضخمة شُيدت فوق جسر، وتوفر إطلالة بانورامية ساحرة على ضفتي النهر في آن واحد.'),
  'tianjin/baozi': ('فطائر غوبولي', 'تُعد هذه الفطائر المطهوة على البخار والمحشوة بلحم الخنزير العلامة المميزة للمدينة منذ أكثر من 150 عاماً.'),
  'tianjin/crosstalk': ('كوميديا شيانغشينغ', 'يُعد فن "الشيانغشينغ" الكوميدي القائم على الحوار بين شخصين تقليداً أصيلاً في تيانجين نشأ في مقاهي الشاي الخاصة بها.'),
  'tianjin/architecture': ('الحي الأوروبي', 'بفضل الفيلات ذات الطراز الأوروبي في منطقة "الجادات الخمس"، اكتسبت المدينة لقب متحف العمارة.'),
  'xiamen/island': ('جزيرة غولانغيو', 'تُعد هذه الجزيرة المدرجة ضمن قائمة اليونسكو متحفاً مفتوحاً بفضل ممراتها الخالية من السيارات وفيلاتها ذات الطراز الاستعماري.'),
  'xiamen/piano': ('جزيرة البيانو', 'تُلقب غولانغيو بـ "جزيرة البيانو" نظراً لامتلاك سكانها أكبر عدد من آلات البيانو للفرد الواحد مقارنة بأي مكان آخر.'),
  'xiamen/egret': ('البلشون الأبيض', 'يُعد طائر البلشون الأبيض رمزاً للمدينة، وهو ما يذكرنا باسمها القديم "جزيرة البلشون".'),
  'xiamen/oyster': ('عجة المحار', 'تُعتبر عجة المحار المقرمشة والمحضرة من المحار الطازج والبيض الطبق الأبرز في المطبخ الساحلي للمدينة.'),
  'harbin/ice': ('مهرجان الجليد', 'يُعد مهرجان الشتاء في هاربين، الذي يضم قصوراً جليدية عملاقة مضاءة، الأكبر من نوعه في العالم.'),
  'harbin/cathedral': ('كاتدرائية القديسة صوفيا', 'تُعد هذه الكاتدرائية الأرثوذكسية الروسية ذات القباب البصلية رمزاً لماضي المدينة الأوروبي.'),
  'harbin/sausage': ('السجق الأحمر', 'يُعتبر السجق الأحمر المدخن على الطريقة الروسية من الأطباق الشهية التي تشتهر بها المدينة منذ قرن من الزمان.'),
  'harbin/accordion': ('مدينة الموسيقى', 'بفضل تراثها الروسي العريق، احتضنت مدينة هاربين أول أوركسترا سيمفونية في الصين.'),
  'fuzhou/alley': ('الأزقة الثلاثة والحارات السبع', 'يُعد هذا الحي القديم بجدرانه البيضاء وقرميده الأسود متحفاً حياً للعمارة التي تعود لعصري مينغ وتشينغ.'),
  'fuzhou/banyan': ('مدينة أشجار البانيان', 'تُلقب فوتشو بمدينة البانيان، حيث تظلل أشجار البانيان العملاقة والقديمة شوارعها.'),
  'fuzhou/hotspring': ('الينابيع الحارة', 'تتدفق الينابيع الحارة في وسط المدينة وتغذي الحمامات العامة منذ ألف عام.'),
  'fuzhou/soup': ('حساء بوذا يقفز فوق الجدار', 'يُعد هذا الحساء الفاخر، المطهو من عشرات المكونات، تحفة المطبخ في مقاطعة فوجيان.'),
  'dongguan/robot': ('مصنع العالم', 'بفضل مصانعها المؤتمتة، تنتج دونغوان حصة ضخمة من الإلكترونيات في العالم.'),
  'dongguan/basketball': ('مدينة كرة السلة', 'يقع مقر أكثر أندية كرة السلة تتويجاً في الصين داخل هذه المدينة التي تُعرف بمدينة كرة السلة.'),
  'dongguan/keyuan': ('حديقة كيوان', 'تُعد واحدة من الحدائق الكلاسيكية الأربع الشهيرة في غوانغدونغ، وتتميز ببركها وأجنحتها الجميلة.'),
  'dongguan/cannon': ('حصون هومين', 'تُشير حصون هومين، حيث بدأت حرب الأفيون، إلى الشاطئ الذي أُحرقت فيه شحنات الأفيون.'),
  'lanzhou/beefnoodle': ('نودلز لانشو باللحم البقري', 'بمرقها الصافي ونودلزها المسحوبة يدوياً، تُعتبر لانشو عاصمة النودلز في الصين.'),
  'lanzhou/waterwheel': ('النواعير المائية', 'ترمز النواعير المائية العملاقة على ضفاف النهر الأصفر إلى قرون من هندسة الري.'),
  'lanzhou/statue': ('تمثال الأم للنهر الأصفر', 'يجسد تمثال الأم وطفلها على ضفة النهر، النهر الذي غذى الحضارة الصينية.'),
  'lanzhou/raft': ('قوارب جلد الغنم', 'لا تزال القوارب التقليدية المصنوعة من جلود الغنم المنفوخة تطفو فوق مياه النهر الأصفر.'),
  'urumqi/bazaar': ('البازار الكبير', 'يتميز البازار بأبراج مآذنه وأكشاك التوابل التي تعكس ألوان طريق الحرير الزاهية.'),
  'urumqi/tianshan': ('بحيرة تيانشي', 'تحيط غابات التنوب ببحيرة تيانشي التي تقع عند سفح قمم جبال تيانشان الثلجية.'),
  'urumqi/kebab': ('كباب لحم الضأن', 'يُعد كباب لحم الضأن المتبل والمشوي على الفحم طبقاً أساسياً على المائدة الأويغورية.'),
  'urumqi/dance': ('الرقص الأويغوري', 'تضفي رقصات الأويغور الدوارة على أنغام الطبول وآلة الرواب البهجة على كل احتفال.'),
  'haikou/coconut': ('مدينة جوز الهند', 'تمنح أشجار جوز الهند التي تصطف على جانبي الشوارع مدينة هايكو لقبها الشهير بمدينة جوز الهند.'),
  'haikou/arcade': ('مباني تشيلو', 'تشكل مباني تشيلو ذات الأعمدة في جنوب الصين ممرات مظللة للمشاة.'),
  'haikou/crater': ('الفوهات البركانية', 'تُشكل الفوهات البركانية الخامدة حديقة جيولوجية خضراء على أطراف المدينة.'),
  'haikou/turtle': ('البحر الاستوائي', 'تجعل المياه الدافئة الصافية والشعاب المرجانية من الساحل موطناً للسلاحف البحرية.'),
  'luoyang/grotto': ('كهوف لونغمن', 'تُعد كهوف لونغمن، التي تضم عشرات الآلاف من تماثيل بوذا المنحوتة في المنحدرات، كنزاً فنياً مدرجاً ضمن قائمة اليونسكو.'),
  'luoyang/peony': ('عاصمة الفاوانيا', 'تزهر آلاف أزهار الفاوانيا في شهر أبريل من كل عام لتجعل من لويانغ عاصمة للفاوانيا.'),
  'luoyang/whitehorse': ('معبد الحصان الأبيض', 'يُعتبر هذا المعبد، الذي تأسس عام 68 ميلادي، أول دير بوذي في الصين.'),
  'luoyang/capital': ('العاصمة القديمة', 'تُعد لويانغ، التي كانت عاصمة لثلاث عشرة سلالة حاكمة، مهداً للحضارة الصينية.'),
  'shantou/gongfutea': ('شاي غونغفو', 'يُعد شاي غونغفو في منطقة تشاوشان فناً من فنون الضيافة، حيث يُحضر بعناية في أكواب صغيرة.'),
  'shantou/beefpot': ('قدر اللحم الساخن', 'يشتهر قدر اللحم الساخن على طريقة تشاوشان، حيث تُطهى شرائح اللحم البقري الطازجة في ثوانٍ معدودة.'),
  'shantou/opera': ('أوبرا تشاوتشو', 'تشتهر أوبرا تشاوتشو التي يعود تاريخها إلى 600 عام بأغانيها الرقيقة وأزيائها المطرزة.'),
  'shantou/harbor': ('ميناء شانتو', 'يُعد هذا الميناء بوابة تاريخية للتجارة البحرية وموطناً للعديد من الصينيين المغتربين.'),
  'baoding/mansion': ('قصر الحاكم', 'يُعتبر هذا القصر أعلى مقر إداري إقليمي في عهد أسرة تشينغ، وهو قاعة حكم محفوظة بعناية.'),
  'baoding/donkeyburger': ('شطيرة لحم الحمير', 'تُعد هذه الشطيرة المكونة من لحم الحمير المتبل داخل خبز مقرمش أشهر مأكولات الشارع في المنطقة.'),
  'baoding/balls': ('كرات الصحة', 'تُعد ممارسة تدوير كرات معدنية في راحة اليد تقليداً قديماً يعود لقرون مضت لتعزيز صحة اليدين.'),
  'baoding/reeds': ('مستنقعات باييانغديان', 'تُعد أكبر منطقة رطبة في شمال الصين، وهي ملاذ للطيور وسط غابات القصب وزهور اللوتس.'),
  'jilin/rime': ('صقيع جيلين', 'يُعتبر الصقيع الأبيض الذي يغطي الأشجار على ضفاف نهر سونغهوا أحد عجائب الطبيعة الأربع في الصين.'),
  'jilin/snowboard': ('منتجع التزلج', 'بفضل ثلوجها الكثيفة وموسمها الطويل، تُعد المدينة واحدة من أفضل وجهات التزلج في شمال البلاد.'),
  'jilin/meteorite': ('متحف النيازك', 'يضم المتحف أكبر نيزك صخري في العالم، والذي سقط على الأرض عام 1976.'),
  'jilin/skate': ('نهر سونغهوا المتجمد', 'يتحول نهر سونغهوا في فصل الشتاء إلى حلبة تزلج طبيعية يرتادها المتزلجون والمتنزهون.'),
  'ordos/khan': ('ضريح جنكيز خان', 'يُعد الضريح المهيب الذي يخلد ذكرى بطل السهوب جنكيز خان قلب الثقافة المغولية.'),
  'ordos/cashmere': ('الكشمير', 'يُصنع الكشمير من صوف ماعز أوردوس، مما جعل المدينة مركزاً عالمياً لصناعة المنسوجات.'),
  'ordos/sanddune': ('الرمال الغنائية', 'تُعد الكثبان الرملية العملاقة التي تصدر طنيناً عند الانزلاق عليها الوجهة المفضلة في صحراء كوبوتشي.'),
  'ordos/yurt': ('الخيمة المغولية', 'ترمز الخيام المصنوعة من اللباد الأبيض والمنصوبة في المراعي الشاسعة إلى حياة البداوة.'),
  'jining/confucius': ('معبد كونفوشيوس', 'يقع المعبد وقصر وضريح الحكيم كونفوشيوس في مدينة تشوفو المجاورة، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'jining/barge': ('القناة الكبرى', 'باعتبارها ميناءً نشطاً على قناة بكين-هانغتشو، كانت جينينغ مركزاً حيوياً لثقافة القنوات المائية.'),
  'jining/sword': ('أبطال ليانغشان', 'تجمع مئة وثمانية من الأبطال الخارجين عن القانون في هذه التلال المستنقعية، كما ورد في رواية "حافة الماء" الكلاسيكية.'),
  'jining/fishnet': ('بحيرة ويشان', 'يلقي الصيادون شباكهم بالطرق التقليدية القديمة في أكبر بحيرة للوتس في شمال الصين.'),
  'langfang/culture': ('مركز ثقافة طريق الحرير', 'يجمع هذا المركز الثقافي الحديث والضخم في المدينة فنون طريق الحرير تحت سقف واحد.'),
  'langfang/furniture': ('مدينة الأثاث', 'تُعد منطقة شيانغخه المجاورة واحدة من أكبر مراكز تصنيع وتجارة الأثاث في الصين.'),
  'langfang/tunnel': ('أنفاق الحرب القديمة', 'تتتبع هذه الأنفاق العسكرية التي حُفرت تحت الأرض منذ ألف عام خطوط الدفاع الحدودية القديمة.'),
  'langfang/themepark': ('منتزه المدينة رقم 1', 'يستقبل هذا المنتزه الترفيهي الواسع العائلات، حيث يعيد تجسيد مدينة قديمة مسورة.'),
  'yancheng/salt': ('مدينة الملح', 'يعني اسم يانتشنغ "حصن الملح"، فقد كانت لقرون مركزاً رئيسياً لإنتاج الملح في الصين.'),
  'yancheng/crane': ('الكركي أحمر التاج', 'تُعد هذه الأراضي الرطبة الساحلية أكبر منطقة شتاء في العالم لطيور الكركي أحمر التاج البرية.'),
  'yancheng/elk': ('أيل الأب ديفيد', 'بعد أن انقرض أيل الميلو في البرية، عاد للتكاثر والعيش من جديد في هذه الأراضي الرطبة.'),
  'yancheng/wetland': ('الأراضي الرطبة الساحلية', 'تُعتبر المسطحات المدية المدرجة ضمن قائمة اليونسكو محطة عالمية للطيور المهاجرة.'),
  'huzhou/brush': ('فرشاة هو للخط', 'تُصنع هنا فرشاة "هو"، التي تُعد واحدة من "الكنوز الأربعة" للخط الصيني التقليدي.'),
  'huzhou/bamboo': ('بحر خيزران أنجي', 'تساهم غابات الخيزران الخضراء الممتدة، التي كانت مصدراً لإلهام العديد من الأفلام، في تلطيف الهواء.'),
  'huzhou/silkworm': ('دودة القز', 'لطالما كان الشاطئ الجنوبي لبحيرة تاي مركزاً لإنتاج حرير التوت منذ ألف عام.'),
  'huzhou/whitetea': ('شاي أنجي الأبيض', 'يُعد شاي أنجي الأبيض، بأوراقه الشاحبة ومذاقه الحلو، من بين أندر أنواع الشاي في الصين.'),
  'quzhou/go': ('لعبة غو', 'تُبجل المدينة باعتبارها "أرض الغو"، وذلك بفضل الأسطورة الشهيرة المرتبطة بجبل لانكي.'),
  'quzhou/peaks': ('جبل جيانغلانغ', 'تشكل الأعمدة الصخرية الثلاثة العملاقة التي تعانق السماء مشهداً طبيعياً فريداً مدرجاً ضمن قائمة اليونسكو.'),
  'quzhou/ponkan': ('يوسفي كوتشو', 'يُعد اليوسفي ذو القشرة الحلوة هدية الشتاء التي تجود بها التلال المعتدلة في كوتشو.'),
  'quzhou/cake': ('الخبز المسطح المخبوز', 'يُعتبر الخبز المسطح المقرمش بالسمسم، والذي يُخبز على جدران الفرن، وجبة إفطار كلاسيكية محلية.'),
  'huainan/tofu': ('مهد التوفو', 'ابتُكر التوفو على جبل باغونغ قبل ألفي عام، ومن هنا انتشر ليصبح جزءاً من المطبخ العالمي.'),
  'huainan/coalmine': ('مدينة الفحم', 'تُعد هواينان قاعدة طاقة رئيسية في شرق الصين بفضل غناها بطبقات الفحم.'),
  'huainan/oldtown': ('مدينة شو القديمة', 'يُعد سور المدينة المحفوظ بالكامل من عهد أسرة سونغ مثالاً نادراً على التصميم الدفاعي القديم.'),
  'huainan/classic': ('كتاب هواينانزي', 'كُتب هذا المرجع الفلسفي الكلاسيكي، الذي جمعه الأمير ليو آن، على هذه الأراضي.'),
  'jingdezhen/porcelain': ('عاصمة الخزف', 'تُلقب المدينة بعاصمة الخزف في العالم، حيث ظلت تنتج الخزف الإمبراطوري لأكثر من ألف عام.'),
  'jingdezhen/kiln': ('الأفران القديمة', 'تحافظ أفران التنين التي تعمل بالحطب على استمرارية الفن التقليدي لصناعة الخزف.'),
  'jingdezhen/bluewhite': ('الخزف الأزرق والأبيض', 'يُعد الخزف الأبيض المزين بنقوش زرقاء من الكوبالت العلامة التجارية الشهيرة للمدينة عالمياً.'),
  'jingdezhen/painting': ('الرسم على الخزف', 'تُقدّر القطع الخزفية التي يرسمها كبار الفنانين بفرش دقيقة كأنها لوحات فنية نفيسة.'),
  'jian/jinggang': ('جبال جينغغانغ', 'تعتبر هذه الجبال الضبابية، التي كانت أول قاعدة للثورة، قلب السياحة الحمراء في الصين.'),
  'jian/torch': ('شرارة الثورة', 'تعد هذه الأرض التي شهدت ولادة مقولة "شرارة واحدة يمكن أن تشعل سهلاً" نصباً تذكارياً تاريخياً.'),
  'jian/academy': ('أكاديمية بايلوتشو', 'خرّجت هذه الأكاديمية التي يعود تاريخها لألف عام، والواقعة على جزيرة في نهر غان، عدداً لا يحصى من العلماء الإمبراطوريين.'),
  'jian/pine': ('صنوبر جينغغانغ', 'ترمز أشجار الصنوبر الحمراء التي ترتفع وسط الضباب إلى روح الجبل والصمود.'),
  'nanping/wuyi': ('جبال وويي', 'تُعد هذه الجبال المدرجة ضمن قائمة اليونسكو كنزاً طبيعياً وثقافياً بفضل منحدراتها الحمراء ووديانها الخضراء.'),
  'nanping/rocktea': ('شاي الصخور', 'يُعتبر شاي أولونغ "الرداء الأحمر الكبير" الذي ينمو بين الصخور من أغلى أنواع الشاي في العالم.'),
  'nanping/bambooraft': ('طوافات النهر المتعرج', 'تنساب طوافات الخيزران بهدوء عبر مجرى النهر المتعرج بين المنحدرات الصخرية الحمراء.'),
  'nanping/scholar': ('المعلم تشو شي', 'درّس تشو شي، مؤسس الكونفوشيوسية الجديدة، عند سفح هذه الجبال.'),
  'shenzhen/skyscraper': ('ناطحات السحاب', 'تُعد غابة ناطحات السحاب التي نشأت من قرية صيد في أربعين عاماً معجزة الإصلاح في الصين.'),
  'shenzhen/chip': ('مدينة التكنولوجيا', 'تُلقب شينزين بـ "وادي السيليكون الصيني" بفضل سوق هواكيانغبي للإلكترونيات وعمالقة التكنولوجيا فيها.'),
  'shenzhen/miniature': ('نافذة على العالم', 'تُعد هذه الحديقة الترفيهية التي تضم نماذج مصغرة لأشهر معالم العالم أيقونة بارزة للمدينة.'),
  'shenzhen/mangrove': ('خليج شينزين', 'يُعتبر الخليج المحاط بأشجار المانغروف ملاذاً آمناً للطيور المهاجرة وطيور البلشون.'),
  'xian/terracotta': ('جيش الطين', 'يُطلق على آلاف الجنود الطينيين الذين يحرسون ضريح الإمبراطور تشين لقب أعجوبة العالم الثامنة.'),
  'xian/citywall': ('سور المدينة', 'يمكن للزوار استكشاف سور مدينة شيان، وهو الأفضل حفظاً من عهد أسرة مينغ، عبر ركوب الدراجات فوق حصونه.'),
  'xian/drumtower': ('برج الجرس', 'يُمثل برج الجرس الذي يعود لعهد أسرة مينغ في وسط المدينة قلب العاصمة القديمة.'),
  'xian/roujiamo': ('روجيامو', 'يُعتبر "الروجيامو"، وهو عبارة عن لحم متبل محشو في خبز مقرمش، النسخة الأصلية من البرغر على طريق الحرير.'),
  'suzhou/garden': ('الحدائق الكلاسيكية', 'تُعد هذه الحدائق المدرجة ضمن قائمة اليونسكو تحفاً فنية مصممة بعناية مع صخور وبرك وأجنحة خشبية.'),
  'suzhou/watertown': ('مدينة المياه', 'تُلقب سوتشو بـ "بندقية الشرق" بفضل قنواتها المائية وجسورها الحجرية ومنازلها البيضاء.'),
  'suzhou/embroidery': ('تطريز سوتشو', 'يُعد التطريز الحريري مزدوج الوجه حرفة تقليدية عريقة في سوتشو يعود تاريخها إلى ألف عام.'),
  'suzhou/kunqu': ('أوبرا كونتشو', 'تُعد أوبرا كونتشو الأنيقة، التي تُعتبر الأم لجميع أنواع الأوبرا الصينية، المهد الفني الذي نشأ في هذه المدينة.'),
  'kunming/stoneforest': ('الغابة الحجرية', 'تشكل أعمدة الحجر الجيري العملاقة، التي نُحتت بفعل عوامل الطبيعة على مدى ملايين السنين، متاهة حجرية غامضة.'),
  'kunming/springcity': ('مدينة الربيع', 'بفضل مناخها المعتدل طوال العام، تُلقب كونمينغ بمدينة الربيع حيث لا تذبل الزهور أبداً.'),
  'kunming/seagull': ('نوارس الرأس الأسود', 'في كل شتاء، تتوافد آلاف النوارس المهاجرة من سيبيريا لتغطي ضفاف البحيرة باللون الأبيض.'),
  'kunming/ricenoodle': ('نودلز عبور الجسر', 'تُعد نودلز الأرز الرفيعة التي تُضاف إلى المرق الساخن عند التقديم الطبق الأشهر في مقاطعة يونان.'),
  'jinan/spring': ('مدينة الينابيع', 'تستمد جينان لقبها من الينابيع الاثنتين والسبعين الشهيرة التي تتدفق من باطن الأرض.'),
  'jinan/daminglake': ('بحيرة دامينغ', 'تتغذى هذه البحيرة الحضرية، التي تحيط بها أشجار الصفصاف وزهور اللوتس، من مياه الينابيع المتدفقة.'),
  'jinan/buddhamountain': ('جبل بوذا الألف', 'يُعد الجبل وجهة للحج بفضل مئات تماثيل بوذا المنحوتة على منحدراته.'),
  'jinan/poet': ('الشاعرة لي تشينغتشاو', 'وُلدت لي تشينغتشاو، أعظم شاعرة في تاريخ الصين، في هذه المدينة التي تُعرف بمدينة الينابيع.'),
  'ningbo/library': ('مكتبة تياني', 'تُعد مكتبة تياني، التي يعود تاريخها إلى 450 عاماً، أقدم مكتبة خاصة لا تزال قائمة في آسيا.'),
  'ningbo/port': ('ميناء الشحن', 'يُصنف ميناء نينغبو-تشوشان كأكثر موانئ العالم ازدحاماً من حيث حمولة البضائع.'),
  'ningbo/tangyuan': ('كرات الأرز الدبق', 'تُعتبر كرات الأرز الدبق المحشوة بالسمسم، والمعروفة باسم تانغ يوان، الحلوى التقليدية المميزة للمدينة.'),
  'ningbo/seafood': ('المأكولات البحرية', 'تعتمد المائدة المحلية في نينغبو بشكل أساسي على أسماك الكروكر الصفراء وسرطان البحر المستخرج من بحر الصين الشرقي.'),
  'shijiazhuang/bridge': ('جسر تشاوتشو', 'يُعد هذا الجسر الحجري المقوس، الذي يبلغ عمره 1400 عام، أقدم جسر ذي فتحات مفتوحة في العالم.'),
  'shijiazhuang/clifftemple': ('جبل تسانغيان', 'يُعتبر المعبد المعلق بين المنحدرات الصخرية خلفية شهيرة للعديد من الأعمال السينمائية.'),
  'shijiazhuang/redbase': ('قاعدة شيبايبو', 'تُعد هذه القرية، التي وُضعت فيها خطط تأسيس الصين الجديدة، وجهة مقدسة للسياحة الحمراء.'),
  'shijiazhuang/pharma': ('مدينة الأدوية', 'تُعتبر المدينة مركزاً رئيسياً لإنتاج المضادات الحيوية، وتضم واحدة من أكبر شركات تصنيع الأدوية في الصين.'),
  'taiyuan/jincitemple': ('معبد جينسي', 'يُعد معبد جينسي، بما يضمه من تماثيل وينابيع يعود تاريخها إلى ثلاثة آلاف عام، أجمل حدائق المعابد في شمال الصين.'),
  'taiyuan/coalcart': ('أرض الفحم', 'تُشكل طبقات الفحم في مقاطعة شانشي عصب الطاقة في الصين، وتُعد تاييوان عاصمة هذا الثراء.'),
  'taiyuan/vinegar': ('الخل المعتق', 'يُعد الخل المعتق المكون الأساسي الذي يمنح المطبخ في مقاطعة شانشي نكهته الحامضة المميزة.'),
  'taiyuan/twinpagoda': ('الباغودا التوأم', 'ترتفع هاتان الباغودتان المثمنتان اللتان تعودان إلى عهد أسرة مينغ جنباً إلى جنب كرمز للمدينة.'),
  'hohhot/lamatemple': ('معبد داتشاو', 'يُعتبر هذا الدير البوذي التبتي، المشهور بتمثال بوذا الفضي، القلب الروحي للمدينة.'),
  'hohhot/dairy': ('عاصمة الألبان', 'وُلدت هنا أكبر العلامات التجارية للألبان في الصين، ولذلك تُلقب المدينة بـ "عاصمة الحليب".'),
  'hohhot/wrestling': ('المصارعة المنغولية', 'تُعد مصارعة "بوخ"، التي تمثل ذروة مهرجان نادام، استعراضاً لقوة أهل السهوب.'),
  'hohhot/prairie': ('المراعي', 'تمتد خارج المدينة مراعي منغوليا الخضراء الشاسعة، التي تعج بالخيول وقطعان الماشية.'),
  'sanya/resortbeach': ('الشاطئ الاستوائي', 'تُشبه رمال خليج يالونغ الناعمة ومياهه الفيروزية جزر هاواي الصينية.'),
  'sanya/guanyin': ('تمثال غوانيين', 'يُعد تمثال غوانيين، الذي يرتفع 108 أمتار فوق سطح البحر، واحداً من أطول تماثيل الآلهة في العالم.'),
  'sanya/diving': ('الغوص', 'تُعد سانيا جنة الغوص في الصين بفضل مياهها الدافئة والصافية وشعابها المرجانية.'),
  'sanya/coconutdrink': ('جوز الهند', 'يُعتبر ماء جوز الهند الطازج المستخرج من البساتين الاستوائية المشروب المنعش للجزيرة.'),
  'yangzhou/slenderlake': ('بحيرة الغرب النحيلة', 'تبدو هذه البحيرة النحيلة، بأشجار الصفصاف وجسرها الأبيض، في غاية الرقة والجمال كأنها لوحة فنية.'),
  'yangzhou/friedrice': ('أرز يانغتشو المقلي', 'يُعد هذا الطبق الكلاسيكي العالمي مزيجاً ذهبياً من الأرز المقلي مع الروبيان والبيض.'),
  'yangzhou/morningtea': ('شاي الصباح', 'تعتبر طقوس تناول وجبة الإفطار الأنيقة المكونة من كعك البخار والشاي جزءاً أصيلاً من ثقافة يانغتشو.'),
  'yangzhou/gegarden': ('حديقة غي', 'تُعد هذه الحديقة التي تضم غابات الخيزران وتجسد الفصول الأربعة عبر الصخور تحفةً في التصميم الكلاسيكي.'),
  'weihai/navalisland': ('جزيرة ليوقونغ', 'بصفتها مقراً لأسطول بييانغ، تشهد هذه الجزيرة على تاريخ القوات البحرية في الصين الحديثة.'),
  'weihai/swan': ('بحيرة البجع', 'تتوافد مئات طيور البجع الصامت من سيبيريا كل شتاء لتزين هذه البحيرة الساحلية.'),
  'weihai/seacucumber': ('خيار البحر', 'يُعتبر خيار البحر الذي ينمو في المياه الباردة والنقية أثمن المأكولات البحرية في المدينة.'),
  'weihai/cape': ('رأس الصين', 'يُعد هذا الرأس الواقع في أقصى شرق الصين المكان الذي تستقبل فيه البلاد أشعة الشمس الأولى.'),
  'handan/taichi': ('تاي تشي', 'تُعتبر بلدة غوانغفو مهد أسلوبي يانغ وو، وهي الموطن الأصلي لرياضة التاي تشي.'),
  'handan/congtai': ('شرفة كونغتاي', 'تطل هذه الشرفة الترابية التي تعود إلى مملكة تشاو القديمة على أكثر من ألفي عام من التاريخ.'),
  'handan/idiom': ('مدينة الأمثال', 'تُلقب هاندان بمدينة الأمثال، حيث نشأت فيها أكثر من 1500 حكمة ومثل صيني.'),
  'handan/ciporcelain': ('خزف تسيجو', 'يُعد خزف تسيجو الذي يتميز بنقوشه السوداء على خلفية بيضاء نموذجاً كلاسيكياً للخزف الشعبي.'),
  'daqing/oilpump': ('حقل النفط', 'تنتشر مضخات النفط المتأرجحة في أرجاء أكبر حقل نفطي في الصين.'),
  'daqing/oilworker': ('الرجل الحديدي', 'تجسد عزيمة بطل عمال النفط وانغ جينشي الروح التأسيسية لهذه المدينة.'),
  'daqing/reedlake': ('الأراضي الرطبة', 'تُعد البحيرات المليئة بالقصب وسط آبار النفط موطناً طبيعياً لطيور الكركي والبجع.'),
  'daqing/hotspring': ('الينابيع الحارة', 'توفر المياه المعدنية الحارة المستخرجة من باطن الأرض استراحة علاجية دافئة في الشمال البارد.'),
  'zibo/bbq': ('مشويات تسيبو', 'تُعد هذه المشويات التي تُطهى على مواقد صغيرة وتُلف في فطائر رقيقة ظاهرة شعبية اجتاحت أرجاء الصين.'),
  'zibo/cuju': ('كوجو', 'تُعتبر الكوجو أقدم شكل من أشكال كرة القدم في العالم، وقد كانت تُمارس في مدينة لينزي عاصمة ولاية تشي القديمة.'),
  'zibo/ceramic': ('سيراميك تسيبو', 'تُعد المدينة مركزاً لصناعة السيراميك في شمال الصين بفضل أفرانها التي يعود تاريخها إلى آلاف السنين.'),
  'zibo/glass': ('الزجاج الملون', 'يُعد "ليولي"، وهو زجاج ملون يُصنع يدوياً من الزجاج المنصهر، حرفة فنية تتلألأ ببريق خاص.'),
  'taian/mounttai': ('جبل تاي', 'يُعد جبل تاي سيد الجبال الخمسة المقدسة، وهو أقدس قمة كان الأباطرة يقدمون عندها القرابين للسماء.'),
  'taian/sunrise': ('شروق الشمس من القمة', 'تُعد مشاهدة شروق الشمس فوق بحر من السحب المكافأة الكبرى لمن يتسلق جبل تاي.'),
  'taian/stonesteps': ('الدرج الحجري', 'تمثل السلالم الحجرية التي يبلغ عددها سبعة آلاف درجة وصولاً إلى القمة اختباراً بدنياً شاقاً في طريق الحجاج.'),
  'taian/daitemple': ('معبد داي', 'يُعد هذا المعبد المهيب الواقع عند سفح الجبل المكان الذي كان الأباطرة يستعدون فيه لمراسم طقوس جبل تاي.'),
  'lianyungang/monkey': ('جبل ملك القردة', 'يقع هنا جبل هواغو، وهو موطن ملك القردة الشهير في رواية رحلة إلى الغرب.'),
  'lianyungang/seaport': ('الميناء البحري', 'يُعتبر الميناء البوابة البحرية الشرقية لطريق الحرير، ويمثل الطرف المطل على المحيط الهادئ للجسر البري الأوراسي.'),
  'lianyungang/mountain': ('جبل يونتاي', 'يُعد جبل يونتاي بقممه الشاهقة وغاباته الكثيفة أعلى جبل في مقاطعة جيانغسو.'),
  'lianyungang/crystal': ('أرض الكريستال', 'تستضيف منطقة دونغهاي المجاورة واحدة من أكبر أسواق بلورات الكوارتز في العالم.'),
  'maanshan/libai': ('الشاعر لي باي', 'تضم هذه المدينة الواقعة على ضفاف النهر المحطة الأخيرة وضريح أعظم شعراء الصين، لي باي.'),
  'maanshan/steel': ('مدينة الصلب', 'جعلت مصانع ماغانغ للصلب من هذه المدينة واحدة من أهم قواعد صناعة الحديد والصلب في الصين.'),
  'maanshan/rivercliff': ('منحدر كايشيجي', 'يُعد هذا المنحدر الذي يغوص في مياه نهر اليانغتسي المشهد الشعري الذي ارتبط بأسطورة الشاعر لي باي.'),
  'maanshan/moonwine': ('القمر والنبيذ', 'لا تزال قصائد لي باي التي تتغنى بالقمر والنبيذ حاضرة في المهرجانات التي تقام على ضفاف النهر.'),
  'longyan/tulou': ('بيوت التولو في يونغدينغ', 'تنتشر في التلال قلاع سكنية دائرية ضخمة بناها شعب الهاكا، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'longyan/redmeeting': ('اجتماع غوتيان', 'شهدت هذه القرية الاجتماع التاريخي الذي رسم المسار المستقبلي للجيش الأحمر.'),
  'longyan/hakka': ('ثقافة الهاكا', 'يحافظ شعب الهاكا، وهم مهاجرون من الشمال، على لغتهم ومأكولاتهم التقليدية في هذه التلال.'),
  'longyan/mountain': ('جبل غوانتشي', 'يُعد هذا الجبل بجروفه الحمراء ومياهه الصافية جوهرة طبيعية في جنوب مقاطعة فوجيان.'),
  'beijing/great-wall': ('سور الصين العظيم', 'أطول تحصين في العالم يمتد لأكثر من 20 ألف كيلومتر، ويُعد قسم بادالينغ القريب من بكين بأسواره الحجرية وأبراجه الأكثر زيارة.'),
  'beijing/temple': ('معبد السماء', 'مجمع مقدس كان أباطرة أسرتي مينغ وتشينغ يقصدونه للصلاة من أجل حصاد وفير، ويتميز بسقفه الأزرق الدائري الذي بُني دون استخدام مسمار واحد.'),
  'beijing/pagoda': ('باغودا تياننينغ', 'تُعد هذه الباغودا المبنية من الطوب في عهد أسرة لياو واحدة من أقدم الهياكل الباقية في بكين، وشاهدة على تاريخ المدينة العريق.'),
  'beijing/opera': ('أوبرا بكين', 'فن مسرحي صيني تقليدي يجمع بين الغناء والحوار والفنون القتالية، وتكشف وجوه الممثلين الملونة عن سمات شخصياتهم، فالأحمر يرمز للولاء والأبيض للمكر.'),
};
